  1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
  2→import { Stage } from 'react-konva';
  3→import { useNavigate } from 'react-router-dom';
  4→import { useAuth } from '../../Context/useAuth';
  5→import { getUniversePosts, getUserData } from '../../../API/Api';
  6→import supabase from '../../utils/supabaseClient';
  7→import useUniverseCamera from './hooks/useUniverseCamera';
  8→import useCosmicGravity from './hooks/useCosmicGravity';
  9→import DeepSpaceLayer from './layers/DeepSpaceLayer';
 10→import MidGalaxyLayer from './layers/MidGalaxyLayer';
 11→import NebulaLayer from './layers/NebulaLayer';
 12→import InteractiveLayer from './layers/InteractiveLayer';
 13→import UniverseMinimap from './components/UniverseMinimap';
 14→import { extractSnippet, MIN_UNIVERSE_ZOOM, userHomeCoords } from './utils/starUtils';
 15→import {
 16→    buildSectorIndex,
 17→    computeGalaxyCentroids,
 18→    computeSectorKey,
 19→    getNeighborSectorKeys,
 20→} from './utils/cosmicPhysics';
 21→import { handleClickProfile } from '../../../helpers/handleClicks';
 22→import styles from './Universe.module.css';
 23→
 24→const SECTOR_SIZE = 2000;
 25→const ENABLE_SETTLED_RPC_SAVE = import.meta.env.VITE_ENABLE_UNIVERSE_SETTLE_SAVE === 'true';
 26→
 27→const Universe = () => {
 28→    const navigate = useNavigate();
 29→    const { user } = useAuth();
 30→    const userId = user?.userData?.[0]?.id || null;
 31→
 32→    const fetchDebounceRef = useRef(null);
 33→    const settleDebounceRef = useRef(null);
 34→    const lastSettledPayloadRef = useRef('');
 35→    const initialFetchResolvedRef = useRef(false);
 36→    const hasAutoFocusedOwnGalaxyRef = useRef(false);
 37→    const ownGalaxyLookupStartedRef = useRef(false);
 38→
 39→    const [posts, setPosts] = useState(new Map());
 40→    const [selectedPost, setSelectedPost] = useState(null);
 41→    const [selectedGalaxy, setSelectedGalaxy] = useState(null);
 42→    const [galaxyProfile, setGalaxyProfile] = useState(null);
 43→    const [pulsingId, setPulsingId] = useState(null);
 44→    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);
 45→    const [isInitialLoading, setIsInitialLoading] = useState(true);
 46→    const [ownGalaxyTarget, setOwnGalaxyTarget] = useState(null);
 47→
 48→    // Gravity data from server (fallback paths when embeddings are unavailable in payload)
 49→    const [centroids, setCentroids] = useState([]);
 50→    const [galaxyEdges, setGalaxyEdges] = useState([]);
 51→    const [similarPairs, setSimilarPairs] = useState([]);
 52→    const [starPulls, setStarPulls] = useState([]);
 53→
 54→    const {
 55→        stageRef, stageSize, camera, zoom, isDragging, centerWorld,
 56→        getLayerProps, getViewportBounds, stageEvents, flyTo, jumpTo, isFlying,
 57→    } = useUniverseCamera(userId, hasOwnPosts);
 58→
 59→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
 60→    const showTitles = zoom > 0.5;
 61→
 62→    // Sector partitioning for scalable local gravity math.
 63→    const postSectorIndex = useMemo(() => (
 64→        buildSectorIndex(
 65→            postArray,
 66→            (post) => ({
 67→                x: post?.display_x ?? post?.universe_x,
 68→                y: post?.display_y ?? post?.universe_y,
 69→            }),
 70→            SECTOR_SIZE
 71→        )
 72→    ), [postArray]);
 73→
 74→    const centerSectorKey = useMemo(
 75→        () => computeSectorKey(centerWorld.x, centerWorld.y, SECTOR_SIZE),
 76→        [centerWorld.x, centerWorld.y]
 77→    );
 78→
 79→    const activeSectorKeys = useMemo(
 80→        () => new Set(getNeighborSectorKeys(centerSectorKey)),
 81→        [centerSectorKey]
 82→    );
 83→
 84→    const activePosts = useMemo(() => {
 85→        if (activeSectorKeys.size === 0) return postArray;
 86→
 87→        const next = [];
 88→        for (const key of activeSectorKeys) {
 89→            const bucket = postSectorIndex.get(key);
 90→            if (bucket?.length) next.push(...bucket);
 91→        }
 92→        return next;
 93→    }, [postArray, postSectorIndex, activeSectorKeys]);
 94→
 95→    const activePostIds = useMemo(() => {
 96→        const ids = new Set();
 97→        for (const post of activePosts) {
 98→            if (post?.id) ids.add(post.id);
 99→        }
100→        return ids;
101→    }, [activePosts]);
102→
103→    const { centroidByUser } = useMemo(
104→        () => computeGalaxyCentroids(postArray),
105→        [postArray]
106→    );
107→
108→    // ── Hash-based galaxies (STARTING positions — always from hash) ──
109→    const hashGalaxies = useMemo(() => {
110→        const seen = new Map();
111→        for (const post of postArray) {
112→            const uid = post.users?.id ?? post.user_id;
113→            if (!uid || seen.has(uid)) continue;
114→            const hash = userHomeCoords(uid);
115→            seen.set(uid, {
116→                userId: uid,
117→                name: post.users?.name ?? post.user_name ?? 'Anonymous',
118→                x: hash.x,
119→                y: hash.y,
120→            });
121→        }
122→        return Array.from(seen.values());
123→    }, [postArray]);
124→
125→    // ── Centroid targets (WHERE galaxies should fly TO) ──────────────
126→    const centroidTargets = useMemo(() => {
127→        const map = new Map();
128→        for (const c of centroids) {
129→            if (c.galaxy_x != null && c.galaxy_y != null) {
130→                map.set(c.user_id, { x: c.galaxy_x, y: c.galaxy_y });
131→            }
132→        }
133→        return map;
134→    }, [centroids]);
135→
136→    // ── Gravity hook: animates galaxies + computes star pull offsets ─
137→    const {
138→        galaxyPositions,
139→        starPullOffsets,
140→        isSettled,
141→        galaxyEdges: effectiveGalaxyEdges,
142→        hasEmbeddingGravity,
143→    } = useCosmicGravity({
144→        galaxies: hashGalaxies,
145→        centroidTargets,
146→        edges: galaxyEdges,
147→        posts: postArray,
148→        starPulls,
149→        centroidByUser,
150→        activeSectorKeys,
151→        activePostIds,
152→        sectorSize: SECTOR_SIZE,
153→    });
154→
155→    // ── Render galaxies = hash galaxies with animated positions ──────
156→    const galaxies = useMemo(() => {
157→        return hashGalaxies.map(g => {
158→            const animated = galaxyPositions.get(g.userId);
159→            return animated ? { ...g, x: animated.x, y: animated.y } : g;
160→        });
161→    }, [hashGalaxies, galaxyPositions]);
162→
163→    const getComputedStarPosition = useCallback((post) => {
164→        if (!post) return null;
165→
166→        const uid = post.users?.id ?? post.user_id;
167→        const hashGal = userHomeCoords(uid);
168→        const animGal = galaxyPositions.get(uid);
169→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
170→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
171→        const pull = starPullOffsets.get(post.id);
172→
173→        const baseX = post.universe_x ?? post.display_x;
174→        const baseY = post.universe_y ?? post.display_y;
175→        if (baseX == null || baseY == null) return null;
176→
177→        return {
178→            x: baseX + galDx + (pull?.dx ?? 0),
179→            y: baseY + galDy + (pull?.dy ?? 0),
180→        };
181→    }, [galaxyPositions, starPullOffsets]);
182→
183→    // Resolve logged-in user's galaxy target independently from viewport data.
184→    useEffect(() => {
185→        if (!userId) return;
186→        if (ownGalaxyLookupStartedRef.current) return;
187→
188→        ownGalaxyLookupStartedRef.current = true;
189→        let cancelled = false;
190→
191→        const resolveOwnGalaxyTarget = async () => {
192→            try {
193→                const { data, error } = await supabase
194→                    .from('galaxy_centroids')
195→                    .select('galaxy_x, galaxy_y')
196→                    .eq('user_id', userId)
197→                    .maybeSingle();
198→
199→                if (cancelled) return;
200→
201→                if (!error && data?.galaxy_x != null && data?.galaxy_y != null) {
202→                    setOwnGalaxyTarget({ x: data.galaxy_x, y: data.galaxy_y });
203→                    setHasOwnPosts(true);
204→                    return;
205→                }
206→            } catch (err) {
207→                console.warn('[universe] own centroid lookup failed:', err?.message || err);
208→            }
209→
210→            if (!cancelled) {
211→                setOwnGalaxyTarget(userHomeCoords(userId));
212→            }
213→        };
214→
215→        resolveOwnGalaxyTarget();
216→
217→        return () => {
218→            cancelled = true;
219→        };
220→    }, [userId]);
221→
222→    // Debounced fetch on camera/zoom change
223→    useEffect(() => {
224→        if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
225→
226→        fetchDebounceRef.current = setTimeout(async () => {
227→            const bounds = getViewportBounds();
228→            try {
229→                const result = await getUniversePosts(
230→                    bounds.minX,
231→                    bounds.maxX,
232→                    bounds.minY,
233→                    bounds.maxY,
234→                    200
235→                );
236→                if (result?.data) {
237→                    setPosts(prev => {
238→                        const next = new Map(prev);
239→                        for (const post of result.data) {
240→                            next.set(post.id, post);
241→                        }
242→                        return next;
243→                    });
244→                    if (userId && hasOwnPosts !== true) {
245→                        const ownsAny = result.data.some(p =>
246→                            (p.users?.id ?? p.user_id) === userId
247→                        );
248→                        if (ownsAny) setHasOwnPosts(true);
249→                    }
250→                }
251→                // Keep server gravity data as fallback when embeddings are absent in payload.
252→                setCentroids(Array.isArray(result?.centroids) ? result.centroids : []);
253→                setGalaxyEdges(Array.isArray(result?.edges) ? result.edges : []);
254→                setSimilarPairs(Array.isArray(result?.similarPairs) ? result.similarPairs : []);
255→                setStarPulls(Array.isArray(result?.starPulls) ? result.starPulls : []);
256→            } catch (err) {
257→                console.error('Failed to fetch universe posts:', err);
258→            } finally {
259→                if (!initialFetchResolvedRef.current) {
260→                    initialFetchResolvedRef.current = true;
261→                    setIsInitialLoading(false);
262→                }
263→            }
264→        }, 400);
265→
266→        return () => {
267→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
268→        };
269→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
270→
271→    const handleStarClick = useCallback((post) => {
272→        if (isFlying.current) return;
273→        setSelectedPost(post);
274→        setSelectedGalaxy(null);
275→        setGalaxyProfile(null);
276→
277→        const position = getComputedStarPosition(post);
278→        if (!position) return;
279→
280→        flyTo(position.x, position.y, 1.2, () => {
281→            setPulsingId(post.id);
282→            setTimeout(() => setPulsingId(null), 700);
283→        });
284→    }, [flyTo, getComputedStarPosition, isFlying]);
285→
286→    const handleGalaxyClick = useCallback(async (galaxy) => {
287→        if (isFlying.current) return;
288→        setSelectedGalaxy(galaxy);
289→        setSelectedPost(null);
290→        setGalaxyProfile(null);
291→        flyTo(galaxy.x, galaxy.y, 0.8);
292→
293→        try {
294→            const data = await getUserData(galaxy.userId);
295→            const profile = data?.userData?.[0] || null;
296→            setGalaxyProfile(profile);
297→        } catch (err) {
298→            console.error('Failed to fetch galaxy profile:', err);
299→        }
300→    }, [flyTo, isFlying]);
301→
302→    const handleReadPost = useCallback(() => {
303→        if (!selectedPost) return;
304→        navigate(`/home/post/${selectedPost.id}`);
305→    }, [selectedPost, navigate]);
306→
307→    const handleMinimapNavigate = useCallback((worldX, worldY, mode = 'fly') => {
308→        if (mode === 'drag') {
309→            jumpTo(worldX, worldY);
310→            return;
311→        }
312→        flyTo(worldX, worldY, zoom);
313→    }, [flyTo, jumpTo, zoom]);
314→
315→    // One-time auto focus after first payload is loaded.
316→    useEffect(() => {
317→        if (!userId) return;
318→        if (isInitialLoading) return;
319→        if (hasAutoFocusedOwnGalaxyRef.current) return;
320→
321→        const ownGalaxy = galaxies.find((galaxy) => galaxy.userId === userId);
322→        const target = ownGalaxy
323→            ? { x: ownGalaxy.x, y: ownGalaxy.y }
324→            : (centroidTargets.get(userId) || ownGalaxyTarget);
325→
326→        // Wait until we have a concrete own target; fallback is resolved asynchronously.
327→        if (!target) return;
328→
329→        hasAutoFocusedOwnGalaxyRef.current = true;
330→        flyTo(target.x, target.y, MIN_UNIVERSE_ZOOM);
331→    }, [userId, isInitialLoading, galaxies, centroidTargets, ownGalaxyTarget, flyTo]);
332→
333→    const settledPayload = useMemo(() => {
334→        if (!isSettled || activePosts.length === 0) return [];
335→
336→        const payload = [];
337→        for (const post of activePosts) {
338→            if (!post?.id) continue;
339→            const pos = getComputedStarPosition(post);
340→            if (!pos || !Number.isFinite(pos.x) || !Number.isFinite(pos.y)) continue;
341→
342→            payload.push({
343→                post_id: post.id,
344→                settled_x: Math.round(pos.x * 100) / 100,
345→                settled_y: Math.round(pos.y * 100) / 100,
346→            });
347→        }
348→
349→        payload.sort((a, b) => String(a.post_id).localeCompare(String(b.post_id)));
350→        return payload;
351→    }, [activePosts, getComputedStarPosition, isSettled]);
352→
353→    // Placeholder persistence hook: debounced Supabase RPC for settled positions.
354→    useEffect(() => {
355→        if (!ENABLE_SETTLED_RPC_SAVE) return;
356→        if (!isSettled || settledPayload.length === 0) return;
357→
358→        const signature = JSON.stringify(settledPayload);
359→        if (signature === lastSettledPayloadRef.current) return;
360→
361→        if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
362→        settleDebounceRef.current = setTimeout(async () => {
363→            lastSettledPayloadRef.current = signature;
364→            try {
365→                const { error } = await supabase.rpc('save_universe_settled_positions', {
366→                    positions_payload: settledPayload,
367→                });
368→                if (error) {
369→                    console.warn('[universe] settle save placeholder RPC returned error:', error.message);
370→                }
371→            } catch (err) {
372→                console.warn('[universe] settle save placeholder RPC failed:', err?.message || err);
373→            }
374→        }, 1200);
375→
376→        return () => {
377→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
378→        };
379→    }, [isSettled, settledPayload]);
380→
381→    useEffect(() => {
382→        return () => {
383→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
384→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
385→        };
386→    }, []);
387→
388→    return (
389→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
390→            <button className={styles.backButton} onClick={() => navigate('/home')}>
391→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
392→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
393→                </svg>
394→                Back
395→            </button>
396→
397→            <div className={styles.coordsLabel}>
398→                {centerWorld.x}, {centerWorld.y}
399→            </div>
400→
401→            {isInitialLoading && (
402→                <div className={styles.loadingOverlay}>
403→                    <div className={styles.loadingCard}>
404→                        <div className={styles.loadingSpinner} />
405→                        <div className={styles.loadingText}>Loading universe...</div>
406→                    </div>
407→                </div>
408→            )}
409→
410→            <Stage
411→                ref={stageRef}
412→                width={stageSize.width}
413→                height={stageSize.height}
414→                {...stageEvents}
415→            >
416→                <DeepSpaceLayer layerProps={getLayerProps(0.1)} />
417→                <MidGalaxyLayer layerProps={getLayerProps(0.4)} />
418→                <NebulaLayer
419→                    layerProps={getLayerProps(0.85)}
420→                    galaxies={galaxies}
421→                    centroids={centroids}
422→                />
423→                <InteractiveLayer
424→                    layerProps={getLayerProps(1.0)}
425→                    posts={postArray}
426→                    galaxies={galaxies}
427→                    zoom={zoom}
428→                    showTitles={showTitles}
429→                    pulsingId={pulsingId}
430→                    onStarClick={handleStarClick}
431→                    onGalaxyClick={handleGalaxyClick}
432→                    galaxyPositions={galaxyPositions}
433→                    starPullOffsets={starPullOffsets}
434→                    similarPairs={similarPairs}
435→                    galaxyEdges={effectiveGalaxyEdges}
436→                    activePostIds={activePostIds}
437→                    useEmbeddingBridges={hasEmbeddingGravity}
438→                />
439→            </Stage>
440→
441→            <UniverseMinimap
442→                galaxies={galaxies}
443→                camera={camera}
444→                zoom={zoom}
445→                stageSize={stageSize}
446→                onNavigate={handleMinimapNavigate}
447→            />
448→
449→            {selectedGalaxy && galaxyProfile && (
450→                <div className={styles.galaxyPreviewPanel}>
451→                    <button
452→                        className={styles.galaxyPreviewClose}
453→                        onClick={() => { setSelectedGalaxy(null); setGalaxyProfile(null); }}
454→                    >
455→                        &times;
456→                    </button>
457→                    <div
458→                        className={styles.galaxyPreviewBg}
459→                        style={galaxyProfile.background || {}}
460→                    />
461→                    <div className={styles.galaxyPreviewContent}>
462→                        <img
463→                            className={styles.galaxyPreviewAvatar}
464→                            src={galaxyProfile.image_url || '/assets/profile.jpg'}
465→                            alt=""
466→                        />
467→                        <div className={styles.galaxyPreviewHeading}>
468→                            This is {galaxyProfile.name || selectedGalaxy.name}'s galaxy
469→                        </div>
470→                        {galaxyProfile.bio && (
471→                            <div className={styles.galaxyPreviewBio}>{galaxyProfile.bio}</div>
472→                        )}
473→                        <button
474→                            className={styles.galaxyPreviewVisitBtn}
475→                            onClick={(e) => handleClickProfile(navigate)(e, userId, selectedGalaxy.userId)}
476→                        >
477→                            Visit Profile
478→                        </button>
479→                    </div>
480→                </div>
481→            )}
482→
483→            {selectedPost && (
484→                <div className={styles.previewPanel}>
485→                    <button
486→                        className={styles.previewClose}
487→                        onClick={() => setSelectedPost(null)}
488→                    >
489→                        &times;
490→                    </button>
491→                    <div className={styles.previewAuthor}>
492→                        <img
493→                            className={styles.previewAvatar}
494→                            src={selectedPost.users?.image_url || selectedPost.user_image_url || '/assets/profile.jpg'}
495→                            alt=""
496→                        />
497→                        <span className={styles.previewAuthorName}>
498→                            {selectedPost.users?.name || selectedPost.user_name || 'Anonymous'}
499→                        </span>
500→                    </div>
501→                    <div className={styles.previewTitle}>{selectedPost.title}</div>
502→                    <div className={styles.previewSnippet}>{extractSnippet(selectedPost)}</div>
503→                    <div className={styles.previewLikes}>
504→                        {(() => {
505→                            const count = selectedPost.like_count != null
506→                                ? selectedPost.like_count
507→                                : (Array.isArray(selectedPost.likes) && selectedPost.likes[0]?.count != null
508→                                    ? selectedPost.likes[0].count : 0);
509→                            return `${count} like${count !== 1 ? 's' : ''}`;
510→                        })()}
511→                    </div>
512→                    <button className={styles.previewReadBtn} onClick={handleReadPost}>
513→                        Read
514→                    </button>
515→                </div>
516→            )}
517→        </div>
518→    );
519→};
520→
521→export default Universe;
522→

