    border-radius: 50%;
    color: rgba(255, 255, 255, 0.7);
    font-size: 16px;
    line-height: 1;
    cursor: pointer;
    transition: background 0.2s, color 0.2s;
    padding: 0;
    font-family: inherit;
}

.previewClose:hover {
    background: rgba(0, 0, 0, 0.6);
    color: #fff;
}

.previewAuthor {
    display: flex;
    align-items: center;
    gap: 10px;
    margin-bottom: 12px;
}

.previewAvatar {
    width: 32px;
