 60→    } = useUniverseCamera(userId, hasOwnPosts);
 61→
 62→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
 63→    const showTitles = zoom > 0.5;
 64→
 65→    // Sector partitioning for scalable local gravity math.
 66→    const postSectorIndex = useMemo(() => (
 67→        buildSectorIndex(
 68→            postArray,
 69→            (post) => ({
 70→                x: post?.display_x ?? post?.universe_x,
 71→                y: post?.display_y ?? post?.universe_y,
 72→            }),
 73→            SECTOR_SIZE
 74→        )
 75→    ), [postArray]);
 76→
 77→    const centerSectorKey = useMemo(
 78→        () => computeSectorKey(centerWorld.x, centerWorld.y, SECTOR_SIZE),
 79→        [centerWorld.x, centerWorld.y]
 80→    );
 81→
 82→    const activeSectorKeys = useMemo(
 83→        () => new Set(getNeighborSectorKeys(centerSectorKey)),
 84→        [centerSectorKey]
 85→    );
 86→
 87→    const activePosts = useMemo(() => {
 88→        if (activeSectorKeys.size === 0) return postArray;
 89→
 90→        const next = [];
 91→        for (const key of activeSectorKeys) {
 92→            const bucket = postSectorIndex.get(key);
 93→            if (bucket?.length) next.push(...bucket);
 94→        }
 95→        return next;
 96→    }, [postArray, postSectorIndex, activeSectorKeys]);
 97→
 98→    const activePostIds = useMemo(() => {
 99→        const ids = new Set();
100→        for (const post of activePosts) {
101→            if (post?.id) ids.add(post.id);
102→        }
103→        return ids;
104→    }, [activePosts]);
105→
106→    const { centroidByUser } = useMemo(
107→        () => computeGalaxyCentroids(postArray),
108→        [postArray]
109→    );
110→
111→    // ── Hash-based galaxies (STARTING positions — always from hash) ──
112→    const hashGalaxies = useMemo(() => {
113→        const seen = new Map();
114→        for (const post of postArray) {
115→            const uid = post.users?.id ?? post.user_id;
116→            if (!uid || seen.has(uid)) continue;
117→            const hash = userHomeCoords(uid);
