244→            } catch (err) {
245→                if (!cancelled) {
246→                    console.warn('[universe] wormhole fetch failed:', err?.message || err);
247→                }
248→            }
249→        };
250→
251→        fetchWormholes();
252→        return () => { cancelled = true; };
253→    }, []);
254→
255→    // Debounced fetch on camera/zoom change
256→    useEffect(() => {
257→        if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
258→
259→        fetchDebounceRef.current = setTimeout(async () => {
260→            const bounds = getViewportBounds();
261→            try {
262→                const result = await getUniversePosts(
263→                    bounds.minX,
