286→                setGalaxyEdges(Array.isArray(result?.edges) ? result.edges : []);
287→                setSimilarPairs(Array.isArray(result?.similarPairs) ? result.similarPairs : []);
288→                setStarPulls(Array.isArray(result?.starPulls) ? result.starPulls : []);
