333→    }, [flyTo, isFlying]);
334→
335→    const handleReadPost = useCallback(() => {
336→        if (!selectedPost) return;
337→        navigate(`/home/post/${selectedPost.id}`);
338→    }, [selectedPost, navigate]);
339→
340→    const handleMinimapNavigate = useCallback((worldX, worldY, mode = 'fly') => {
341→        if (mode === 'drag') {
