382→
383→            payload.push({
384→                post_id: post.id,
385→                settled_x: Math.round(pos.x * 100) / 100,
386→                settled_y: Math.round(pos.y * 100) / 100,
387→            });
388→        }
389→
390→        payload.sort((a, b) => String(a.post_id).localeCompare(String(b.post_id)));
391→        return payload;
392→    }, [activePosts, getComputedStarPosition, isSettled]);
393→
394→    // Placeholder persistence hook: debounced Supabase RPC for settled positions.
395→    useEffect(() => {
396→        if (!ENABLE_SETTLED_RPC_SAVE) return;
397→        if (!isSettled || settledPayload.length === 0) return;
398→
399→        const signature = JSON.stringify(settledPayload);
