401→
402→        if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
403→        settleDebounceRef.current = setTimeout(async () => {
404→            lastSettledPayloadRef.current = signature;
405→            try {
406→                const { error } = await supabase.rpc('save_universe_settled_positions', {
407→                    positions_payload: settledPayload,
408→                });
409→                if (error) {
410→                    console.warn('[universe] settle save placeholder RPC returned error:', error.message);
411→                }
412→            } catch (err) {
413→                console.warn('[universe] settle save placeholder RPC failed:', err?.message || err);
414→            }
415→        }, 1200);
416→
417→        return () => {
418→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
419→        };
