421→
422→    useEffect(() => {
423→        return () => {
424→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
425→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
426→        };
427→    }, []);
428→
429→    return (
430→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
431→            <button className={styles.backButton} onClick={() => navigate('/home')}>
432→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
433→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
434→                </svg>
435→                Back
436→            </button>
437→
438→            <div className={styles.coordsLabel}>
439→                {centerWorld.x}, {centerWorld.y}
440→            </div>
441→
442→            {isInitialLoading && (
443→                <div className={styles.loadingOverlay}>
444→                    <div className={styles.loadingCard}>
445→                        <div className={styles.loadingSpinner} />
446→                        <div className={styles.loadingText}>Loading universe...</div>
447→                    </div>
448→                </div>
449→            )}
450→
451→            <Stage
452→                ref={stageRef}
453→                width={stageSize.width}
454→                height={stageSize.height}
455→                {...stageEvents}
456→            >
457→                <DeepSpaceLayer layerProps={getLayerProps(0.1)} />
458→                <MidGalaxyLayer layerProps={getLayerProps(0.4)} />
459→                <NebulaLayer
460→                    layerProps={getLayerProps(0.85)}
461→                    galaxies={galaxies}
462→                    centroids={centroids}
463→                />
464→                <InteractiveLayer
465→                    layerProps={getLayerProps(1.0)}
466→                    posts={postArray}
467→                    galaxies={galaxies}
468→                    zoom={zoom}
469→                    showTitles={showTitles}
470→                    pulsingId={pulsingId}
471→                    onStarClick={handleStarClick}
472→                    onGalaxyClick={handleGalaxyClick}
473→                    galaxyPositions={galaxyPositions}
474→                    starPullOffsets={starPullOffsets}
475→                    similarPairs={similarPairs}
476→                    galaxyEdges={effectiveGalaxyEdges}
477→                    activePostIds={activePostIds}
