489→
490→            {isWarping && <div className={styles.warpOverlay} />}
491→
492→            <UniverseMinimap
493→                galaxies={galaxies}
494→                camera={camera}
495→                zoom={zoom}
496→                stageSize={stageSize}
497→                onNavigate={handleMinimapNavigate}
498→            />
499→
500→            {selectedGalaxy && galaxyProfile && (
501→                <div className={styles.galaxyPreviewPanel}>
502→                    <button
503→                        className={styles.galaxyPreviewClose}
504→                        onClick={() => { setSelectedGalaxy(null); setGalaxyProfile(null); }}
505→                    >
506→                        &times;
507→                    </button>
508→                    <div
509→                        className={styles.galaxyPreviewBg}
510→                        style={galaxyProfile.background || {}}
