        for (let a = 0; a < ARC_COUNT; a++) {
            const speed = 0.0008 + a * 0.0003;
            const arcRadius = radius * (0.5 + a * 0.25);
            const startAngle = time * speed + phaseOffset + (a * TWO_PI / ARC_COUNT);
            const sweep = Math.PI * 0.4;

            ctx.beginPath();
            ctx.arc(x, y, arcRadius, startAngle, startAngle + sweep);
            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},${(0.4 - a * 0.06) * opacity})`;
            ctx.lineWidth = 2 - a * 0.3;
            ctx.stroke();
        }

        // Orbiting particle dots
        for (let p = 0; p < PARTICLE_COUNT; p++) {
            const orbitSpeed = 0.0012 + p * 0.0002;
            const orbitRadius = radius * (0.4 + (p / PARTICLE_COUNT) * 0.8);
            const angle = time * orbitSpeed + phaseOffset + (p * TWO_PI / PARTICLE_COUNT);
            const px = x + Math.cos(angle) * orbitRadius;
            const py = y + Math.sin(angle) * orbitRadius;
            const particleAlpha = (0.5 + 0.3 * Math.sin(time * 0.002 + p)) * opacity;

            ctx.beginPath();
            ctx.arc(px, py, 1.5, 0, TWO_PI);
            ctx.fillStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},${particleAlpha})`;
            ctx.fill();
        }

        // Bright core dot
        ctx.beginPath();
        ctx.arc(x, y, 3, 0, TWO_PI);
        ctx.fillStyle = `rgba(255,255,255,${0.6 * opacity})`;
        ctx.fill();
    };

    return (
        <Layer {...layerProps}>
            {/* Batch-drawn vortex visuals */}
            <Shape
                ref={shapeRef}
                sceneFunc={(ctx) => {
                    const time = animRef.current.time;
                    for (const vortex of vortexData) {
                        drawVortex(ctx, vortex.a_x, vortex.a_y, vortex.rgb, time, vortex.phaseA);
                        drawVortex(ctx, vortex.b_x, vortex.b_y, vortex.rgb, time, vortex.phaseB);
                    }
                }}
                perfectDrawEnabled={false}
                listening={false}
            />
            {/* Invisible hit-detection circles per endpoint */}
            {vortexData.map((wh, i) => (
                <React.Fragment key={`wh-${i}`}>
                    <Circle
                        x={wh.a_x}
                        y={wh.a_y}
                        radius={20 / zoom}
                        opacity={0}
                        onMouseEnter={(e) => {
                            const container = e.target.getStage().container();
                            container.style.cursor = 'pointer';
                        }}
                        onMouseLeave={(e) => {
                            const container = e.target.getStage().container();
                            container.style.cursor = 'grab';
                        }}
                        onClick={() => onWormholeClick(wh, 'a')}
                        onTap={() => onWormholeClick(wh, 'a')}
                    />
                    <Circle
                        x={wh.b_x}
                        y={wh.b_y}
                        radius={20 / zoom}
                        opacity={0}
                        onMouseEnter={(e) => {
                            const container = e.target.getStage().container();
                            container.style.cursor = 'pointer';
                        }}
                        onMouseLeave={(e) => {
                            const container = e.target.getStage().container();
                            container.style.cursor = 'grab';
                        }}
                        onClick={() => onWormholeClick(wh, 'b')}
                        onTap={() => onWormholeClick(wh, 'b')}
                    />
                </React.Fragment>
            ))}
        </Layer>
    );
});

WormholeLayer.displayName = 'WormholeLayer';

export default WormholeLayer;

