 41→            const color = STAR_COLORS[i % STAR_COLORS.length];
 42→            const rgb = parseHex(color);
 43→            // Use post_a ID hash for stable phase offsets (not random)
 44→            const hashVal = wh.post_a ? parseInt(wh.post_a.slice(0, 8), 16) : i * 12345;
 45→            return {
