    display: inline-block;
    padding: 8px 22px;
    background: rgba(95, 146, 255, 0.15);
    border: 1px solid rgba(95, 146, 255, 0.4);
    border-radius: 10px;
    color: #5f92ff;
    font-size: 13px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.previewReadBtn:hover {
    background: rgba(95, 146, 255, 0.25);
    border-color: rgba(95, 146, 255, 0.6);
}

.previewActions {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.wormholeBtn {
    display: inline-block;
    padding: 8px 22px;
    background: rgba(180, 95, 255, 0.15);
    border: 1px solid rgba(180, 95, 255, 0.4);
    border-radius: 10px;
    color: #b05fff;
    font-size: 12px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.wormholeBtn:hover {
    background: rgba(180, 95, 255, 0.25);
    border-color: rgba(180, 95, 255, 0.6);
}

