import React, { useRef, useEffect, useCallback, useMemo } from 'react';
import { Layer, Shape } from 'react-konva';
import { STAR_COLORS } from '../utils/starUtils';

const TWO_PI = Math.PI * 2;
const RING_COUNT = 3;
const SPIRAL_ARMS = 2;
const SPIRAL_PARTICLES = 12;
const OUTER_PARTICLE_COUNT = 8;

/** Parse "#5f92ff" → { r, g, b } */
const parseHex = (hex) => ({
    r: parseInt(hex.slice(1, 3), 16),
    g: parseInt(hex.slice(3, 5), 16),
    b: parseInt(hex.slice(5, 7), 16),
});

/** Lerp between two RGB colors */
const lerpRgb = (a, b, t) => ({
    r: Math.round(a.r + (b.r - a.r) * t),
    g: Math.round(a.g + (b.g - a.g) * t),
    b: Math.round(a.b + (b.b - a.b) * t),
});

const WHITE = { r: 255, g: 255, b: 255 };

const WormholeLayer = React.memo(({ layerProps, wormholes, zoom }) => {
    const animRef = useRef({ time: 0 });
    const shapeRef = useRef(null);
    const rafRef = useRef(null);

    // Always visible, slightly dimmer when zoomed in
    const opacity = zoom < 0.15 ? 1.0
        : zoom < 0.8 ? 1.0 - (zoom - 0.15) * 0.4
        : 0.74;

    // Pre-compute vortex data with colors and stable phase offsets
    const vortexData = useMemo(() => {
        if (!Array.isArray(wormholes)) return [];
        return wormholes.map((wh, i) => {
            const color = STAR_COLORS[i % STAR_COLORS.length];
            const rgb = parseHex(color);
            const hashVal = wh.post_a ? parseInt(wh.post_a.slice(0, 8), 16) : i * 12345;
            return {
                ...wh,
                color,
                rgb,
                phaseA: (hashVal % 1000) / 1000 * TWO_PI,
                phaseB: ((hashVal * 7) % 1000) / 1000 * TWO_PI,
            };
        });
    }, [wormholes]);

    const animate = useCallback(() => {
        animRef.current.time = performance.now();
        if (shapeRef.current) {
            shapeRef.current.getLayer()?.batchDraw();
        }
        rafRef.current = requestAnimationFrame(animate);
    }, []);

    useEffect(() => {
        if (vortexData.length === 0) return;
        rafRef.current = requestAnimationFrame(animate);
        return () => {
            if (rafRef.current) cancelAnimationFrame(rafRef.current);
        };
    }, [animate, vortexData.length]);

    if (vortexData.length === 0) return null;

    const drawVortex = (ctx, x, y, rgb, time, phaseOffset, radius) => {
        const breathe = 1.0 + 0.15 * Math.sin(time * 0.0008 + phaseOffset);
        const r = radius * breathe;

        // Outer ambient glow
        const outerGlow = ctx.createRadialGradient(x, y, 0, x, y, r * 2.5);
        outerGlow.addColorStop(0, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.12 * opacity})`);
        outerGlow.addColorStop(0.5, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.04 * opacity})`);
        outerGlow.addColorStop(1, 'rgba(0,0,0,0)');
        ctx.beginPath();
        ctx.arc(x, y, r * 2.5, 0, TWO_PI);
        ctx.fillStyle = outerGlow;
        ctx.fill();

        // Dark center void (the "hole")
        const voidGrad = ctx.createRadialGradient(x, y, 0, x, y, r * 0.45);
        voidGrad.addColorStop(0, `rgba(0,0,0,${0.7 * opacity})`);
        voidGrad.addColorStop(0.7, `rgba(0,0,0,${0.3 * opacity})`);
        voidGrad.addColorStop(1, 'rgba(0,0,0,0)');
        ctx.beginPath();
        ctx.arc(x, y, r * 0.45, 0, TWO_PI);
        ctx.fillStyle = voidGrad;
        ctx.fill();

        // Concentric rotating rings (event horizon)
        for (let ring = 0; ring < RING_COUNT; ring++) {
            const ringRadius = r * (0.5 + ring * 0.28);
            const rotSpeed = 0.0006 * (ring % 2 === 0 ? 1 : -1) * (1 + ring * 0.3);
            const rot = time * rotSpeed + phaseOffset + ring * 0.8;
            const ringAlpha = (0.35 - ring * 0.08) * opacity;

            const segments = 6 + ring * 2;
            const gapRatio = 0.35;
            const segSweep = TWO_PI / segments * (1 - gapRatio);

            ctx.lineWidth = Math.max(1.5 - ring * 0.3, 0.6);
            const c = lerpRgb(rgb, WHITE, 0.2 - ring * 0.08);
            ctx.strokeStyle = `rgba(${c.r},${c.g},${c.b},${ringAlpha})`;

            for (let s = 0; s < segments; s++) {
                const start = rot + (s * TWO_PI / segments);
                ctx.beginPath();
                ctx.arc(x, y, ringRadius, start, start + segSweep);
                ctx.stroke();
            }
        }

        // Spiral arms — particles spiraling inward
        for (let arm = 0; arm < SPIRAL_ARMS; arm++) {
            const armOffset = (arm * TWO_PI) / SPIRAL_ARMS;
            for (let p = 0; p < SPIRAL_PARTICLES; p++) {
                const t = p / SPIRAL_PARTICLES;
                const spiralAngle = armOffset + t * TWO_PI * 1.5 + time * 0.001 + phaseOffset;
                const spiralR = r * (0.3 + t * 0.9);
                const px = x + Math.cos(spiralAngle) * spiralR;
                const py = y + Math.sin(spiralAngle) * spiralR;
                const pAlpha = (0.15 + 0.35 * (1 - t)) * opacity;
                const pSize = 1.0 + 1.5 * (1 - t);

                ctx.beginPath();
                ctx.arc(px, py, pSize, 0, TWO_PI);
                const pc = lerpRgb(rgb, WHITE, 0.5 * (1 - t));
                ctx.fillStyle = `rgba(${pc.r},${pc.g},${pc.b},${pAlpha})`;
                ctx.fill();
            }
        }

        // Outer orbiting particles
        for (let p = 0; p < OUTER_PARTICLE_COUNT; p++) {
            const orbitSpeed = 0.0004 + (p % 3) * 0.0002;
            const dir = p % 2 === 0 ? 1 : -1;
            const orbitR = r * (1.1 + (p / OUTER_PARTICLE_COUNT) * 0.6);
            const angle = time * orbitSpeed * dir + phaseOffset + (p * TWO_PI / OUTER_PARTICLE_COUNT);
            const px = x + Math.cos(angle) * orbitR;
            const py = y + Math.sin(angle) * orbitR;
            const pAlpha = (0.3 + 0.2 * Math.sin(time * 0.002 + p * 1.3)) * opacity;

            ctx.beginPath();
            ctx.arc(px, py, 1.2, 0, TWO_PI);
            ctx.fillStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},${pAlpha})`;
            ctx.fill();
        }

        // Bright core — white hot center point
        const coreGrad = ctx.createRadialGradient(x, y, 0, x, y, r * 0.15);
        coreGrad.addColorStop(0, `rgba(255,255,255,${0.8 * opacity})`);
        coreGrad.addColorStop(0.5, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.4 * opacity})`);
        coreGrad.addColorStop(1, 'rgba(0,0,0,0)');
        ctx.beginPath();
        ctx.arc(x, y, r * 0.15, 0, TWO_PI);
        ctx.fillStyle = coreGrad;
        ctx.fill();
    };

    const drawConnection = (ctx, ax, ay, bx, by, rgb, time) => {
        const dx = bx - ax;
        const dy = by - ay;
        const dist = Math.sqrt(dx * dx + dy * dy) || 1;

        const mx = (ax + bx) / 2;
        const my = (ay + by) / 2;
        const perpX = (-dy / dist) * dist * 0.08;
        const perpY = (dx / dist) * dist * 0.08;

        const dashPhase = time * 0.05;

        ctx.save();
        ctx.setLineDash([8, 12]);
        ctx.lineDashOffset = -dashPhase;
        ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},${0.12 * opacity})`;
