  1→import { mulberry32 } from './proceduralGeneration';
  2→import { simpleHash, hexToRgba } from './starUtils';
  3→
  4→// Parse hex color to {r, g, b}
  5→const hexToRgb = (hex) => ({
  6→    r: parseInt(hex.slice(1, 3), 16),
  7→    g: parseInt(hex.slice(3, 5), 16),
  8→    b: parseInt(hex.slice(5, 7), 16),
  9→});
 10→
 11→// Lerp between two {r,g,b} objects
 12→const lerpColor = (a, b, t) => ({
 13→    r: Math.round(a.r + (b.r - a.r) * t),
 14→    g: Math.round(a.g + (b.g - a.g) * t),
 15→    b: Math.round(a.b + (b.b - a.b) * t),
 16→});
 17→
 18→const WARM = hexToRgb('#ffd7a0');
 19→const COOL = hexToRgb('#4a7fff');
 20→
 21→/**
 22→ * Generate deterministic spiral galaxy data for a user.
 23→ * All positions are relative to (0,0) — caller offsets by galaxy center.
 24→ */
 25→export const generateGalaxyData = (userId) => {
 26→    const seed = simpleHash(userId) + 7919;
 27→    const rng = mulberry32(seed);
 28→
 29→    const armCount = 2 + Math.floor(rng() * 3); // 2-4
 30→    const rotation = rng() * Math.PI * 2;
 31→    const axialTilt = 0.45 + rng() * 0.3; // 0.45-0.75
 32→    const winding = 2.5 + rng() * 1.5; // 2.5-4.0
 33→    const galaxyRadius = 250 + rng() * 100; // 250-350
 34→    const coreSize = 0.18 + rng() * 0.1; // 0.18-0.28
 35→    const coreRadius = galaxyRadius * coreSize;
 36→
 37→    // Pre-compute arm particles
 38→    const particleCount = 300;
 39→    const particles = new Array(particleCount);
 40→
 41→    for (let i = 0; i < particleCount; i++) {
 42→        const armIndex = i % armCount;
 43→        const t = rng() * winding;
 44→        const progress = t / winding; // 0 = core, 1 = outer edge
 45→
 46→        // Archimedean spiral
 47→        const r = coreRadius + (galaxyRadius - coreRadius) * progress;
 48→        const theta = t + (armIndex / armCount) * Math.PI * 2 + rotation;
 49→
 50→        // Scatter perpendicular to arm — wider at outer edges
 51→        const spread = 8 + progress * 35;
 52→        const scatter = (rng() - 0.5) * 2 * spread;
 53→        const tangentAngle = theta + Math.PI / 2;
 54→
 55→        const x = r * Math.cos(theta) + scatter * Math.cos(tangentAngle);
 56→        const y = (r * Math.sin(theta) + scatter * Math.sin(tangentAngle)) * axialTilt;
 57→
 58→        const dotRadius = 0.6 + rng() * 1.8;
 59→        const alpha = 0.15 + rng() * 0.45;
 60→
 61→        particles[i] = { x, y, radius: dotRadius, progress, alpha };
 62→    }
 63→
 64→    // Pre-compute arm curve polylines for glow strokes
 65→    const armCurves = [];
 66→    const curveSteps = 40;
 67→    for (let a = 0; a < armCount; a++) {
 68→        const points = new Array(curveSteps);
 69→        for (let s = 0; s < curveSteps; s++) {
 70→            const t = (s / (curveSteps - 1)) * winding;
 71→            const r = coreRadius + (galaxyRadius - coreRadius) * (t / winding);
 72→            const theta = t + (a / armCount) * Math.PI * 2 + rotation;
 73→            points[s] = {
 74→                x: r * Math.cos(theta),
 75→                y: r * Math.sin(theta) * axialTilt,
 76→            };
 77→        }
 78→        armCurves.push(points);
 79→    }
 80→
 81→    return { galaxyRadius, coreRadius, axialTilt, particles, armCurves };
 82→};
 83→
 84→/**
 85→ * Draw all galaxy visuals + connection lines onto a single canvas context.
 86→ * Each entry in `galaxies` must have: x, y, color, galaxyRadius, coreRadius, particles, armCurves.
 87→ * Optional `edges` array: [{user_a, user_b, similarity}] for similarity-based connections.
 88→ * Optional `galaxyUserIdMap`: Map<userId, galaxyIndex> for edge lookups.
 89→ */
 90→export const drawGalaxyVisuals = (ctx, galaxies, edges, galaxyUserIdMap) => {
 91→    if (!galaxies || galaxies.length === 0) return;
 92→
 93→    // --- Draw each galaxy ---
 94→    for (let g = 0; g < galaxies.length; g++) {
 95→        const gal = galaxies[g];
 96→        const { x: cx, y: cy, color, galaxyRadius, coreRadius, particles, armCurves } = gal;
 97→        const accent = hexToRgb(color);
 98→
 99→        // 1. Outer halo
100→        const haloGrad = ctx.createRadialGradient(cx, cy, coreRadius, cx, cy, galaxyRadius * 1.2);
101→        haloGrad.addColorStop(0, hexToRgba(color, 0.08));
102→        haloGrad.addColorStop(0.6, hexToRgba(color, 0.03));
103→        haloGrad.addColorStop(1, 'rgba(0,0,0,0)');
104→        ctx.fillStyle = haloGrad;
105→        ctx.beginPath();
106→        ctx.arc(cx, cy, galaxyRadius * 1.2, 0, Math.PI * 2);
107→        ctx.fill();
108→
109→        // 2. Arm particles
110→        for (let i = 0; i < particles.length; i++) {
111→            const p = particles[i];
112→            // Color: inner = warm lerp with accent, outer = cool lerp with accent
113→            let c;
114→            if (p.progress < 0.5) {
115→                const t = p.progress / 0.5;
116→                c = lerpColor(WARM, accent, t);
117→            } else {
118→                const t = (p.progress - 0.5) / 0.5;
119→                c = lerpColor(accent, COOL, t);
120→            }
121→            ctx.fillStyle = `rgba(${c.r},${c.g},${c.b},${p.alpha})`;
122→            ctx.beginPath();
123→            ctx.arc(cx + p.x, cy + p.y, p.radius, 0, Math.PI * 2);
124→            ctx.fill();
125→        }
126→
127→        // 3. Arm glow lines
128→        ctx.strokeStyle = hexToRgba(color, 0.08);
129→        ctx.lineWidth = 1.5;
130→        for (let a = 0; a < armCurves.length; a++) {
131→            const pts = armCurves[a];
132→            ctx.beginPath();
133→            ctx.moveTo(cx + pts[0].x, cy + pts[0].y);
134→            for (let s = 1; s < pts.length; s++) {
135→                ctx.lineTo(cx + pts[s].x, cy + pts[s].y);
136→            }
137→            ctx.stroke();
138→        }
139→
140→        // 4. Core glow — multi-stop radial gradient
141→        const coreGrad = ctx.createRadialGradient(cx, cy, 0, cx, cy, coreRadius * 2);
142→        coreGrad.addColorStop(0, 'rgba(255,255,255,0.9)');
143→        coreGrad.addColorStop(0.15, 'rgba(255,248,220,0.6)');
144→        coreGrad.addColorStop(0.5, hexToRgba(color, 0.3));
145→        coreGrad.addColorStop(1, 'rgba(0,0,0,0)');
146→        ctx.fillStyle = coreGrad;
147→        ctx.beginPath();
148→        ctx.arc(cx, cy, coreRadius * 2, 0, Math.PI * 2);
149→        ctx.fill();
150→    }
151→
152→    // --- Connection lines ---
153→    if (edges && edges.length > 0 && galaxyUserIdMap) {
154→        // Similarity-based connections from galaxy_edges
155→        for (const edge of edges) {
156→            const idxA = galaxyUserIdMap.get(edge.user_a);
157→            const idxB = galaxyUserIdMap.get(edge.user_b);
158→            if (idxA == null || idxB == null) continue;
159→
160→            const a = galaxies[idxA];
161→            const b = galaxies[idxB];
162→            const dx = b.x - a.x;
163→            const dy = b.y - a.y;
164→            const dist = Math.sqrt(dx * dx + dy * dy) || 1;
165→
166→            // Opacity and width scale with similarity
167→            const opacity = 0.04 + edge.similarity * 0.08;
168→            const width = 0.3 + edge.similarity * 0.7;
169→
170→            const mx = (a.x + b.x) / 2;
171→            const my = (a.y + b.y) / 2;
172→            const perpX = -dy / dist * dist * 0.08;
173→            const perpY = dx / dist * dist * 0.08;
174→
175→            ctx.strokeStyle = `rgba(150,200,255,${opacity})`;
176→            ctx.lineWidth = width;
177→            ctx.beginPath();
178→            ctx.moveTo(a.x, a.y);
179→            ctx.quadraticCurveTo(mx + perpX, my + perpY, b.x, b.y);
180→            ctx.stroke();
181→        }
182→    } else {
183→        // Fallback: distance-based connections
184→        const MAX_DIST = 5000;
185→        const MAX_DIST_SQ = MAX_DIST * MAX_DIST;
186→
187→        for (let i = 0; i < galaxies.length; i++) {
188→            for (let j = i + 1; j < galaxies.length; j++) {
189→                const a = galaxies[i];
190→                const b = galaxies[j];
191→                const dx = b.x - a.x;
192→                const dy = b.y - a.y;
193→                const distSq = dx * dx + dy * dy;
194→                if (distSq > MAX_DIST_SQ) continue;
195→
196→                const dist = Math.sqrt(distSq);
197→                const fade = 1 - dist / MAX_DIST;
198→                const opacity = 0.06 * fade;
199→
200→                const mx = (a.x + b.x) / 2;
201→                const my = (a.y + b.y) / 2;
202→                const perpX = -dy / dist * dist * 0.1;
203→                const perpY = dx / dist * dist * 0.1;
204→
205→                ctx.strokeStyle = `rgba(255,255,255,${opacity})`;
206→                ctx.lineWidth = 0.5;
207→                ctx.beginPath();
208→                ctx.moveTo(a.x, a.y);
209→                ctx.quadraticCurveTo(mx + perpX, my + perpY, b.x, b.y);
210→                ctx.stroke();
211→            }
212→        }
213→    }
214→};
215→

  1→import React, { useRef, useEffect, useCallback } from 'react';
  2→import { Layer, Shape } from 'react-konva';
  3→import embeddingToColor from '../utils/embeddingToColor';
  4→import { getStarColor } from '../utils/starUtils';
  5→
  6→const TWO_PI = Math.PI * 2;
  7→const BREATH_PERIOD = 10000; // 10-second full cycle
  8→const ROTATION_SPEED = 0.002; // degrees per frame
  9→const BASE_RADIUS = 400;
 10→const RADIUS_PER_POST = 50;
 11→const MAX_EXTRA_POSTS = 4;
 12→
 13→/** Parse "#5f92ff" → { r, g, b } */
 14→const parseHex = (hex) => ({
 15→    r: parseInt(hex.slice(1, 3), 16),
 16→    g: parseInt(hex.slice(3, 5), 16),
 17→    b: parseInt(hex.slice(5, 7), 16),
 18→});
 19→
 20→const NebulaLayer = React.memo(({ layerProps, galaxies, centroids }) => {
 21→    const animRef = useRef({ phase: 0, rotations: [] });
 22→    const shapeRef = useRef(null);
 23→    const rafRef = useRef(null);
 24→
 25→    // Build nebula data: position + RGB color for each galaxy
 26→    const nebulaData = React.useMemo(() => {
 27→        const centroidMap = new Map();
 28→        if (Array.isArray(centroids)) {
 29→            for (const c of centroids) {
 30→                centroidMap.set(c.user_id, c);
 31→            }
 32→        }
 33→
 34→        const data = [];
 35→        if (!Array.isArray(galaxies)) return data;
 36→
 37→        for (const galaxy of galaxies) {
 38→            const centroid = centroidMap.get(galaxy.userId);
 39→            const embedding = centroid?.mean_embedding;
 40→            const rgb = embeddingToColor(embedding) || parseHex(getStarColor(galaxy.userId));
 41→            const postCount = Math.min(centroid?.post_count ?? 0, MAX_EXTRA_POSTS);
 42→            const radius = BASE_RADIUS + postCount * RADIUS_PER_POST;
 43→
 44→            data.push({
 45→                x: galaxy.x,
 46→                y: galaxy.y,
 47→                radius,
 48→                r: rgb.r,
 49→                g: rgb.g,
 50→                b: rgb.b,
 51→            });
 52→        }
 53→
 54→        return data;
 55→    }, [galaxies, centroids]);
 56→
 57→    // Initialize per-cloud rotation offsets when data changes
 58→    useEffect(() => {
 59→        animRef.current.rotations = nebulaData.map(() => Math.random() * 360);
 60→    }, [nebulaData]);
 61→
 62→    // Breathing animation loop
 63→    const animate = useCallback(() => {
 64→        const anim = animRef.current;
 65→        anim.phase = (performance.now() % BREATH_PERIOD) / BREATH_PERIOD;
 66→
 67→        for (let i = 0; i < anim.rotations.length; i++) {
 68→            anim.rotations[i] += ROTATION_SPEED;
 69→        }
 70→
 71→        if (shapeRef.current) {
 72→            shapeRef.current.getLayer()?.batchDraw();
 73→        }
 74→
 75→        rafRef.current = requestAnimationFrame(animate);
 76→    }, []);
 77→
 78→    useEffect(() => {
 79→        rafRef.current = requestAnimationFrame(animate);
 80→        return () => {
 81→            if (rafRef.current) cancelAnimationFrame(rafRef.current);
 82→        };
 83→    }, [animate]);
 84→
 85→    return (
 86→        <Layer {...layerProps} listening={false}>
 87→            <Shape
 88→                ref={shapeRef}
 89→                sceneFunc={(ctx) => {
 90→                    const anim = animRef.current;
 91→                    const scale = 1.0 + 0.15 * Math.sin(anim.phase * TWO_PI);
 92→
 93→                    for (let i = 0; i < nebulaData.length; i++) {
 94→                        const cloud = nebulaData[i];
 95→                        const rot = (anim.rotations[i] || 0) * (Math.PI / 180);
 96→                        const r = cloud.radius * scale;
 97→
 98→                        ctx.save();
 99→                        ctx.translate(cloud.x, cloud.y);
100→                        ctx.rotate(rot);
101→
102→                        const grad = ctx.createRadialGradient(0, 0, 0, 0, 0, r);
103→                        grad.addColorStop(0, `rgba(${cloud.r},${cloud.g},${cloud.b},0.18)`);
104→                        grad.addColorStop(0.5, `rgba(${cloud.r},${cloud.g},${cloud.b},0.08)`);
105→                        grad.addColorStop(1, 'rgba(0,0,0,0)');
106→
107→                        ctx.beginPath();
108→                        ctx.arc(0, 0, r, 0, TWO_PI);
109→                        ctx.fillStyle = grad;
110→                        ctx.fill();
111→
112→                        ctx.restore();
113→                    }
114→                }}
115→                perfectDrawEnabled={false}
116→                listening={false}
117→            />
118→        </Layer>
119→    );
120→});
121→
122→NebulaLayer.displayName = 'NebulaLayer';
123→
124→export default NebulaLayer;
125→

  1→import React, { useMemo } from 'react';
  2→import { Layer, Group, Text, Shape } from 'react-konva';
  3→import StarGroup from '../components/StarGroup';
  4→import { getStarColor, getStarRadius, userHomeCoords } from '../utils/starUtils';
  5→import { generateGalaxyData, drawGalaxyVisuals } from '../utils/galaxyVisuals';
  6→import { computeSemanticBridges } from '../utils/cosmicPhysics';
  7→
  8→const GalaxyLabel = React.memo(({ x, y, name, zoom, onClick }) => {
  9→    const invZoom = 1 / zoom;
 10→    return (
 11→        <Group x={x} y={y} scaleX={invZoom} scaleY={invZoom}>
 12→            <Text
 13→                text={name}
 14→                fontSize={14}
 15→                fill="rgba(255,255,255,0.45)"
 16→                fontStyle="600"
 17→                fontFamily="inherit"
 18→                align="center"
 19→                width={200}
 20→                offsetX={100}
 21→                y={-24}
 22→                perfectDrawEnabled={false}
 23→                onMouseEnter={(e) => {
 24→                    e.target.fill('rgba(255,255,255,0.75)');
 25→                    const container = e.target.getStage().container();
 26→                    container.style.cursor = 'pointer';
 27→                }}
 28→                onMouseLeave={(e) => {
 29→                    e.target.fill('rgba(255,255,255,0.45)');
 30→                    const container = e.target.getStage().container();
 31→                    container.style.cursor = 'grab';
 32→                }}
 33→                onClick={onClick}
 34→                onTap={onClick}
 35→            />
 36→        </Group>
 37→    );
 38→});
 39→
 40→GalaxyLabel.displayName = 'GalaxyLabel';
 41→
 42→const InteractiveLayer = React.memo(({
 43→    layerProps, posts, galaxies, zoom, showTitles, pulsingId,
 44→    onStarClick, onGalaxyClick,
 45→    galaxyPositions, starPullOffsets, similarPairs, galaxyEdges,
 46→    activePostIds, useEmbeddingBridges
 47→}) => {
 48→    // Build userId→index map for edge lookups in drawGalaxyVisuals
 49→    const galaxyUserIdMap = useMemo(() => {
 50→        const map = new Map();
 51→        galaxies?.forEach((g, i) => map.set(g.userId, i));
 52→        return map;
 53→    }, [galaxies]);
 54→
 55→    // Galaxy spiral visuals — positioned at animated galaxy coords
 56→    const galaxyVisuals = useMemo(() =>
 57→        galaxies?.map(g => ({
 58→            x: g.x,
 59→            y: g.y,
 60→            ...generateGalaxyData(g.userId),
 61→            color: getStarColor(g.userId),
 62→        })) || []
 63→    , [galaxies]);
 64→
 65→    // ── Compute every star's render position ─────────────────────────
 66→    // Stars follow their parent galaxy's displacement from hash→animated,
 67→    // plus an optional pull offset toward similar galaxy centroids.
 68→    const computedStarPositions = useMemo(() => {
 69→        const map = new Map();
 70→        for (const post of posts) {
 71→            const uid = post.users?.id ?? post.user_id;
 72→
 73→            // Galaxy displacement: how far the galaxy moved from hash to animated
 74→            const hashGal = userHomeCoords(uid);
 75→            const animGal = galaxyPositions?.get(uid);
 76→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 77→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 78→
 79→            // Star pull offset (Gravity B)
 80→            const pull = starPullOffsets?.get(post.id);
 81→
 82→            // Base position = original hash+spiral coords
 83→            const baseX = post.universe_x ?? post.display_x;
 84→            const baseY = post.universe_y ?? post.display_y;
 85→
 86→            map.set(post.id, {
 87→                x: baseX + galDx + (pull?.dx ?? 0),
 88→                y: baseY + galDy + (pull?.dy ?? 0),
 89→            });
 90→        }
 91→        return map;
 92→    }, [posts, galaxyPositions, starPullOffsets]);
 93→
 94→    const bridgePairs = useMemo(() => {
 95→        const maxPairs = 120;
 96→
 97→        if (useEmbeddingBridges) {
 98→            const bridgePosts = (activePostIds instanceof Set && activePostIds.size > 0)
 99→                ? posts.filter((post) => activePostIds.has(post?.id))
100→                : posts;
101→            return computeSemanticBridges(bridgePosts, computedStarPositions, 0.9, maxPairs);
102→        }
103→
104→        if (!Array.isArray(similarPairs) || similarPairs.length === 0) return [];
105→
106→        return similarPairs
107→            .filter((pair) => Number(pair?.similarity) > 0.9)
108→            .filter((pair) => {
109→                if (!(activePostIds instanceof Set) || activePostIds.size === 0) return true;
110→                return activePostIds.has(pair?.post_a) && activePostIds.has(pair?.post_b);
111→            })
112→            .slice(0, maxPairs);
113→    }, [useEmbeddingBridges, activePostIds, posts, computedStarPositions, similarPairs]);
114→
115→    return (
116→        <Layer {...layerProps}>
117→            {/* Semantic bridges between similar posts */}
118→            {bridgePairs.length > 0 && (
119→                <Shape
120→                    sceneFunc={(ctx) => {
121→                        for (const pair of bridgePairs) {
122→                            const posA = computedStarPositions.get(pair.post_a);
123→                            const posB = computedStarPositions.get(pair.post_b);
124→                            if (!posA || !posB) continue;
125→
126→                            const dx = posB.x - posA.x;
127→                            const dy = posB.y - posA.y;
128→                            const dist = Math.sqrt(dx * dx + dy * dy) || 1;
129→
130→                            const mx = (posA.x + posB.x) / 2;
131→                            const my = (posA.y + posB.y) / 2;
132→                            const perpX = (-dy / dist) * dist * 0.06;
133→                            const perpY = (dx / dist) * dist * 0.06;
134→
135→                            ctx.strokeStyle = 'rgba(150,200,255,0.1)';
136→                            ctx.lineWidth = 0.8;
137→                            ctx.shadowColor = 'rgba(150,200,255,0.3)';
138→                            ctx.shadowBlur = 4;
139→                            ctx.beginPath();
140→                            ctx.moveTo(posA.x, posA.y);
141→                            ctx.quadraticCurveTo(mx + perpX, my + perpY, posB.x, posB.y);
142→                            ctx.stroke();
143→                        }
144→                        ctx.shadowBlur = 0;
145→                    }}
146→                    perfectDrawEnabled={false}
147→                    listening={false}
148→                />
149→            )}
150→            {/* Spiral galaxy visuals + connection lines */}
151→            <Shape
152→                sceneFunc={(ctx) => { drawGalaxyVisuals(ctx, galaxyVisuals, galaxyEdges, galaxyUserIdMap); }}
153→                perfectDrawEnabled={false}
154→                listening={false}
155→            />
156→            {/* Galaxy name labels */}
157→            {galaxies?.map((g) => (
158→                <GalaxyLabel
159→                    key={g.userId}
160→                    x={g.x}
161→                    y={g.y}
162→                    name={g.name}
163→                    zoom={zoom}
164→                    onClick={() => onGalaxyClick(g)}
165→                />
166→            ))}
167→            {/* Stars */}
168→            {posts.map((post) => {
169→                const postUserId = post.users?.id ?? post.user_id;
170→                const color = getStarColor(postUserId);
171→                const likeCount = post.like_count != null
172→                    ? post.like_count
173→                    : (Array.isArray(post.likes) && post.likes[0]?.count != null ? post.likes[0].count : 0);
174→                const radius = getStarRadius(likeCount);
175→
176→                const pos = computedStarPositions.get(post.id);
177→                const x = pos?.x ?? post.universe_x ?? post.display_x;
178→                const y = pos?.y ?? post.universe_y ?? post.display_y;
179→
180→                return (
181→                    <StarGroup
182→                        key={post.id}
183→                        x={x}
184→                        y={y}
185→                        radius={radius}
186→                        color={color}
187→                        title={post.title}
188→                        showTitle={showTitles}
189→                        isPulsing={pulsingId === post.id}
190→                        onClick={() => onStarClick(post)}
191→                    />
192→                );
193→            })}
194→        </Layer>
195→    );
196→});
197→
198→InteractiveLayer.displayName = 'InteractiveLayer';
199→
200→export default InteractiveLayer;
201→

  1→import { mulberry32 } from './proceduralGeneration';
  2→import { simpleHash, hexToRgba } from './starUtils';
  3→
  4→// Parse hex color to {r, g, b}
  5→const hexToRgb = (hex) => ({
  6→    r: parseInt(hex.slice(1, 3), 16),
  7→    g: parseInt(hex.slice(3, 5), 16),
  8→    b: parseInt(hex.slice(5, 7), 16),
  9→});
 10→
 11→// Lerp between two {r,g,b} objects
 12→const lerpColor = (a, b, t) => ({
 13→    r: Math.round(a.r + (b.r - a.r) * t),
 14→    g: Math.round(a.g + (b.g - a.g) * t),
 15→    b: Math.round(a.b + (b.b - a.b) * t),
 16→});
 17→
 18→const WARM = hexToRgb('#ffd7a0');
 19→const COOL = hexToRgb('#4a7fff');
 20→
 21→/**
 22→ * Generate deterministic spiral galaxy data for a user.
 23→ * All positions are relative to (0,0) — caller offsets by galaxy center.
 24→ */
 25→export const generateGalaxyData = (userId) => {
 26→    const seed = simpleHash(userId) + 7919;
 27→    const rng = mulberry32(seed);
 28→
 29→    const armCount = 2 + Math.floor(rng() * 3); // 2-4
 30→    const rotation = rng() * Math.PI * 2;
 31→    const axialTilt = 0.45 + rng() * 0.3; // 0.45-0.75
 32→    const winding = 2.5 + rng() * 1.5; // 2.5-4.0
 33→    const galaxyRadius = 250 + rng() * 100; // 250-350
 34→    const coreSize = 0.18 + rng() * 0.1; // 0.18-0.28
 35→    const coreRadius = galaxyRadius * coreSize;
 36→
 37→    // Pre-compute arm particles
 38→    const particleCount = 300;
 39→    const particles = new Array(particleCount);
 40→
 41→    for (let i = 0; i < particleCount; i++) {
 42→        const armIndex = i % armCount;
 43→        const t = rng() * winding;
 44→        const progress = t / winding; // 0 = core, 1 = outer edge
 45→
 46→        // Archimedean spiral
 47→        const r = coreRadius + (galaxyRadius - coreRadius) * progress;
 48→        const theta = t + (armIndex / armCount) * Math.PI * 2 + rotation;
 49→
 50→        // Scatter perpendicular to arm — wider at outer edges
 51→        const spread = 8 + progress * 35;
 52→        const scatter = (rng() - 0.5) * 2 * spread;
 53→        const tangentAngle = theta + Math.PI / 2;
 54→
 55→        const x = r * Math.cos(theta) + scatter * Math.cos(tangentAngle);
 56→        const y = (r * Math.sin(theta) + scatter * Math.sin(tangentAngle)) * axialTilt;
 57→
 58→        const dotRadius = 0.6 + rng() * 1.8;
 59→        const alpha = 0.15 + rng() * 0.45;
 60→
 61→        particles[i] = { x, y, radius: dotRadius, progress, alpha };
 62→    }
 63→
 64→    // Pre-compute arm curve polylines for glow strokes
 65→    const armCurves = [];
 66→    const curveSteps = 40;
 67→    for (let a = 0; a < armCount; a++) {
 68→        const points = new Array(curveSteps);
 69→        for (let s = 0; s < curveSteps; s++) {
 70→            const t = (s / (curveSteps - 1)) * winding;
 71→            const r = coreRadius + (galaxyRadius - coreRadius) * (t / winding);
 72→            const theta = t + (a / armCount) * Math.PI * 2 + rotation;
 73→            points[s] = {
 74→                x: r * Math.cos(theta),
 75→                y: r * Math.sin(theta) * axialTilt,
 76→            };
 77→        }
 78→        armCurves.push(points);
 79→    }
 80→
 81→    return { galaxyRadius, coreRadius, axialTilt, particles, armCurves };
 82→};
 83→
 84→/**
 85→ * Draw all galaxy visuals + connection lines onto a single canvas context.
 86→ * Each entry in `galaxies` must have: x, y, color, galaxyRadius, coreRadius, particles, armCurves.
 87→ * Optional `edges` array: [{user_a, user_b, similarity}] for similarity-based connections.
 88→ * Optional `galaxyUserIdMap`: Map<userId, galaxyIndex> for edge lookups.
 89→ */
 90→export const drawGalaxyVisuals = (ctx, galaxies, edges, galaxyUserIdMap) => {
 91→    if (!galaxies || galaxies.length === 0) return;
 92→
 93→    // --- Draw each galaxy ---
 94→    for (let g = 0; g < galaxies.length; g++) {
 95→        const gal = galaxies[g];
 96→        const { x: cx, y: cy, color, galaxyRadius, coreRadius, particles, armCurves } = gal;
 97→        const accent = hexToRgb(color);
 98→
 99→        // 1. Outer halo
100→        const haloGrad = ctx.createRadialGradient(cx, cy, coreRadius, cx, cy, galaxyRadius * 1.2);
101→        haloGrad.addColorStop(0, hexToRgba(color, 0.08));
102→        haloGrad.addColorStop(0.6, hexToRgba(color, 0.03));
103→        haloGrad.addColorStop(1, 'rgba(0,0,0,0)');
104→        ctx.fillStyle = haloGrad;
105→        ctx.beginPath();
106→        ctx.arc(cx, cy, galaxyRadius * 1.2, 0, Math.PI * 2);
107→        ctx.fill();
108→
109→        // 2. Arm particles
110→        for (let i = 0; i < particles.length; i++) {
111→            const p = particles[i];
112→            // Color: inner = warm lerp with accent, outer = cool lerp with accent
113→            let c;
114→            if (p.progress < 0.5) {
115→                const t = p.progress / 0.5;
116→                c = lerpColor(WARM, accent, t);
117→            } else {
118→                const t = (p.progress - 0.5) / 0.5;
119→                c = lerpColor(accent, COOL, t);
120→            }
121→            ctx.fillStyle = `rgba(${c.r},${c.g},${c.b},${p.alpha})`;
122→            ctx.beginPath();
123→            ctx.arc(cx + p.x, cy + p.y, p.radius, 0, Math.PI * 2);
124→            ctx.fill();
125→        }
126→
127→        // 3. Arm glow lines
128→        ctx.strokeStyle = hexToRgba(color, 0.08);
129→        ctx.lineWidth = 1.5;
130→        for (let a = 0; a < armCurves.length; a++) {
131→            const pts = armCurves[a];
132→            ctx.beginPath();
133→            ctx.moveTo(cx + pts[0].x, cy + pts[0].y);
134→            for (let s = 1; s < pts.length; s++) {
135→                ctx.lineTo(cx + pts[s].x, cy + pts[s].y);
136→            }
137→            ctx.stroke();
138→        }
139→
140→        // 4. Core glow — multi-stop radial gradient
141→        const coreGrad = ctx.createRadialGradient(cx, cy, 0, cx, cy, coreRadius * 2);
142→        coreGrad.addColorStop(0, 'rgba(255,255,255,0.9)');
143→        coreGrad.addColorStop(0.15, 'rgba(255,248,220,0.6)');
144→        coreGrad.addColorStop(0.5, hexToRgba(color, 0.3));
145→        coreGrad.addColorStop(1, 'rgba(0,0,0,0)');
146→        ctx.fillStyle = coreGrad;
147→        ctx.beginPath();
148→        ctx.arc(cx, cy, coreRadius * 2, 0, Math.PI * 2);
149→        ctx.fill();
150→    }
151→
152→    // --- Connection lines ---
153→    if (edges && edges.length > 0 && galaxyUserIdMap) {
154→        // Similarity-based connections from galaxy_edges
155→        for (const edge of edges) {
156→            const idxA = galaxyUserIdMap.get(edge.user_a);
157→            const idxB = galaxyUserIdMap.get(edge.user_b);
158→            if (idxA == null || idxB == null) continue;
159→
160→            const a = galaxies[idxA];
161→            const b = galaxies[idxB];
162→            const dx = b.x - a.x;
163→            const dy = b.y - a.y;
164→            const dist = Math.sqrt(dx * dx + dy * dy) || 1;
165→
166→            // Opacity and width scale with similarity
167→            const opacity = 0.04 + edge.similarity * 0.08;
168→            const width = 0.3 + edge.similarity * 0.7;
169→
170→            const mx = (a.x + b.x) / 2;
171→            const my = (a.y + b.y) / 2;
172→            const perpX = -dy / dist * dist * 0.08;
173→            const perpY = dx / dist * dist * 0.08;
174→
175→            ctx.strokeStyle = `rgba(150,200,255,${opacity})`;
176→            ctx.lineWidth = width;
177→            ctx.beginPath();
178→            ctx.moveTo(a.x, a.y);
179→            ctx.quadraticCurveTo(mx + perpX, my + perpY, b.x, b.y);
180→            ctx.stroke();
181→        }
182→    } else {
183→        // Fallback: distance-based connections
184→        const MAX_DIST = 5000;
185→        const MAX_DIST_SQ = MAX_DIST * MAX_DIST;
186→
187→        for (let i = 0; i < galaxies.length; i++) {
188→            for (let j = i + 1; j < galaxies.length; j++) {
189→                const a = galaxies[i];
190→                const b = galaxies[j];
191→                const dx = b.x - a.x;
192→                const dy = b.y - a.y;
193→                const distSq = dx * dx + dy * dy;
194→                if (distSq > MAX_DIST_SQ) continue;
195→
196→                const dist = Math.sqrt(distSq);
197→                const fade = 1 - dist / MAX_DIST;
198→                const opacity = 0.06 * fade;
199→
200→                const mx = (a.x + b.x) / 2;
201→                const my = (a.y + b.y) / 2;
202→                const perpX = -dy / dist * dist * 0.1;
203→                const perpY = dx / dist * dist * 0.1;
204→
205→                ctx.strokeStyle = `rgba(255,255,255,${opacity})`;
206→                ctx.lineWidth = 0.5;
207→                ctx.beginPath();
208→                ctx.moveTo(a.x, a.y);
209→                ctx.quadraticCurveTo(mx + perpX, my + perpY, b.x, b.y);
210→                ctx.stroke();
211→            }
212→        }
213→    }
214→};
