  1→import React, { useRef, useEffect, useCallback, useMemo } from 'react';
  2→import { Layer, Shape } from 'react-konva';
  3→import { simpleHash, getStarColor } from '../utils/starUtils';
  4→
  5→const TWO_PI = Math.PI * 2;
  6→const DUST_PER_GALAXY = 60;
  7→
  8→/** Parse "#5f92ff" → { r, g, b } */
  9→const parseHex = (hex) => ({
 10→    r: parseInt(hex.slice(1, 3), 16),
 11→    g: parseInt(hex.slice(3, 5), 16),
 12→    b: parseInt(hex.slice(5, 7), 16),
 13→});
 14→
 15→/** Seeded RNG (same as proceduralGeneration) */
 16→const seededRng = (seed) => {
 17→    let s = seed | 0;
 18→    return () => {
 19→        s = (s + 0x6D2B79F5) | 0;
 20→        let t = Math.imul(s ^ (s >>> 15), 1 | s);
 21→        t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
 22→        return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
 23→    };
 24→};
 25→
 26→const StardustLayer = React.memo(({ layerProps, galaxies }) => {
 27→    const animRef = useRef({ time: 0 });
 28→    const shapeRef = useRef(null);
 29→    const rafRef = useRef(null);
 30→
 31→    // Generate deterministic dust particles for each galaxy
 32→    const dustData = useMemo(() => {
 33→        if (!Array.isArray(galaxies) || galaxies.length === 0) return [];
 34→
 35→        const allDust = [];
 36→
 37→        for (const galaxy of galaxies) {
 38→            const seed = simpleHash(galaxy.userId) + 3571;
 39→            const rng = seededRng(seed);
 40→            const color = getStarColor(galaxy.userId);
 41→            const rgb = parseHex(color);
 42→            const galaxyRadius = 250 + (rng() * 100);
 43→
 44→            for (let i = 0; i < DUST_PER_GALAXY; i++) {
 45→                // Distribute in a disc with falloff — more in the arms, some beyond
 46→                const angle = rng() * TWO_PI;
 47→                const dist = galaxyRadius * (0.15 + rng() * 1.1);
 48→
 49→                // Offset from galaxy center
 50→                const localX = Math.cos(angle) * dist;
 51→                const localY = Math.sin(angle) * dist * (0.5 + rng() * 0.4); // flatten for tilt
 52→
 53→                // Each particle has unique animation params
 54→                const twinkleSpeed = 0.0008 + rng() * 0.002;
 55→                const twinklePhase = rng() * TWO_PI;
 56→                const driftSpeed = 0.00003 + rng() * 0.00008;
 57→                const driftAngle = rng() * TWO_PI;
 58→                const driftRadius = 3 + rng() * 12;
 59→                const baseAlpha = 0.08 + rng() * 0.35;
 60→                const size = 0.4 + rng() * 1.6;
 61→
 62→                // Color variation: mix galaxy color with white/warm tones
 63→                const warmMix = rng();
 64→                const r = Math.round(rgb.r + (255 - rgb.r) * warmMix * 0.5);
 65→                const g = Math.round(rgb.g + (248 - rgb.g) * warmMix * 0.4);
 66→                const b = Math.round(rgb.b + (220 - rgb.b) * warmMix * 0.3);
 67→
 68→                allDust.push({
 69→                    gx: galaxy.x,
 70→                    gy: galaxy.y,
 71→                    localX,
 72→                    localY,
 73→                    twinkleSpeed,
 74→                    twinklePhase,
 75→                    driftSpeed,
 76→                    driftAngle,
 77→                    driftRadius,
 78→                    baseAlpha,
 79→                    size,
 80→                    r, g, b,
 81→                });
 82→            }
 83→        }
 84→
 85→        return allDust;
 86→    }, [galaxies]);
 87→
 88→    const animate = useCallback(() => {
 89→        animRef.current.time = performance.now();
 90→        if (shapeRef.current) {
 91→            shapeRef.current.getLayer()?.batchDraw();
 92→        }
 93→        rafRef.current = requestAnimationFrame(animate);
 94→    }, []);
 95→
 96→    useEffect(() => {
 97→        if (dustData.length === 0) return;
 98→        rafRef.current = requestAnimationFrame(animate);
 99→        return () => {
100→            if (rafRef.current) cancelAnimationFrame(rafRef.current);
101→        };
102→    }, [animate, dustData.length]);
103→
104→    if (dustData.length === 0) return null;
105→
106→    return (
107→        <Layer {...layerProps} listening={false}>
108→            <Shape
109→                ref={shapeRef}
110→                sceneFunc={(ctx) => {
111→                    const time = animRef.current.time;
112→
113→                    for (let i = 0; i < dustData.length; i++) {
114→                        const d = dustData[i];
