const BREATH_PERIOD = 10000;
const ROTATION_SPEED = 0.002;
const BASE_RADIUS = 400;
const RADIUS_PER_POST = 50;
const MAX_EXTRA_POSTS = 4;
const DUST_PER_GALAXY = 60;

