240→                }
241→                console.log('[universe] wormhole pairs:', data);
242→                if (Array.isArray(data) && data.length > 0) {
243→                    setWormholes(data);
244→                }
245→            } catch (err) {
246→                if (!cancelled) {
247→                    console.warn('[universe] wormhole fetch failed:', err?.message || err);
248→                }
249→            }
